const response = $input.first().json;
const workflows = response.data || response || [];
const now = new Date().toISOString();

const allWorkflows = Array.isArray(workflows) ? workflows : [];
const bigWorkflows = allWorkflows.filter(wf => {
  const tags = wf.tags || [];
  return tags.some(t => {
    const name = typeof t === 'object' ? t.name : t;
    return name === 'BIG';
  });
});

if (bigWorkflows.length === 0) {
  throw new Error('No workflows with the BIG tag were found. Total workflows returned: ' + allWorkflows.length);
}

return bigWorkflows.map(wf => {
  const exportObj = {
    id: wf.id,
    name: wf.name,
    nodes: wf.nodes || [],
    connections: wf.connections || {},
    settings: wf.settings || {},
    pinData: {},
    tags: (wf.tags || []).map(t => typeof t === 'object' ? t.name : t),
  };
  const slug = wf.name
    .replace(/[^a-zA-Z0-9 -]/g, '')
    .trim()
    .replace(/ +/g, '-');
  return {
    json: {
      workflow_id: wf.id,
      workflow_name: wf.name,
      file_path: slug + '.json',
      version_id: wf.versionId || null,
      version_counter: wf.versionCounter || null,
      active: wf.active,
      export_json: JSON.stringify(exportObj, null, 2),
      backup_timestamp: now,
    }
  };
});

const ghResponse = $input.first().json;
const exp = $('Process One at a Time').first().json;
const existingSha = ghResponse.sha || null;
const isUpdate = !!existingSha;
const content = Buffer.from(exp.export_json, 'utf-8').toString('base64');
const action = isUpdate ? 'update' : 'create';
const message = action + ': ' + exp.workflow_name +
  '\n\nWorkflow ID: ' + exp.workflow_id +
  '\nVersion: ' + (exp.version_counter || 'unknown') +
  '\nActive: ' + exp.active +
  '\nBackup: ' + exp.backup_timestamp;
const body = { message: message, content: content };
if (existingSha) {
  body.sha = existingSha;
}
return [{
  json: {
    file_path: exp.file_path,
    workflow_name: exp.workflow_name,
    workflow_id: exp.workflow_id,
    action: action,
    commit_body: body,
  }
}];

return [{
  json: {
    status: 'complete',
    backup_timestamp: new Date().toISOString(),
    repository: 'berenczeiricsi/n8n-workflows',
    message: 'All BIG workflows have been backed up to GitHub. Check the repository commit history for details.',
  }
}];
